use std::collections::HashMap;

struct ColumnData {
    data: Vec<i32>,
}

impl ColumnData {
    fn new(data: Vec<i32>) -> Self {
        ColumnData { data }
    }

    fn run_length_encode(&self) -> Vec<(i32, usize)> {
        if self.data.is_empty() {
            return Vec::new();
        }

        let mut encoded = Vec::new();
        let mut current_value = self.data[0];
        let mut count = 1;

        for &next_value in self.data.iter().skip(1) {
            if next_value == current_value {
                count += 1;
            } else {
                encoded.push((current_value, count));
                current_value = next_value;
                count = 1;
            }
        }
        encoded.push((current_value, count));
        encoded
    }
}

fn main() {
    let raw_data = vec![5, 5, 5, 2, 2, 8, 8, 8, 8, 1];
    let column = ColumnData::new(raw_data);
    let encoded_sequence = column.run_length_encode();

    println!("Encoded sequence: ");
    for (value, count) in &encoded_sequence {
        println!("Value: {}, Count: {}", value, count);
    }
}

use std::collections::VecDeque;

struct Instruction {
    name: String,
    args: Vec<i32>,
}

fn execute_bytecode(instructions: &[Instruction]) -> Option<i32> {
    let mut stack: Vec<i32> = Vec::new();

    for instruction in instructions {
        match instruction.name.as_str() { 
            "PUSH" => {
                if let Some(arg) = instruction.args.get(0) {
                    stack.push(*arg);
                }
            }
            "ADD" => {
                if stack.len() >= 2 {
                    let b = stack.pop().unwrap();
                    let a = stack.pop().unwrap();
                    stack.push(a + b);
                } else {
                    return None;
                }
            }
            "PRINT_TOP" => {
                if let Some(result) = stack.last() {
                    println!("Result: {}", result);
                    return Some(*result);
                } else {
                    return Some(0); 
                }
            }
            _ => { 
                continue;
            }
        }
    }

    stack.pop()
}

use std::collections::VecDeque;

struct SlidingWindowDetector {
    window_size: usize,
    data_queue: VecDeque<f64>,
}

impl SlidingWindowDetector {
    fn new(window_size: usize) -> Self {
        SlidingWindowDetector {
            window_size,
            data_queue: VecDeque::with_capacity(window_size),
        }
    }

    fn add_and_check(&mut self, new_value: f64) -> Option<f64> {
        if self.data_queue.len() < self.window_size - 1 {
            self.data_queue.push_back(new_value);
            return None;
        }

        self.data_queue.pop_front();
        self.data_queue.push_back(new_value);

        let window: Vec<f64> = self.data_queue.iter().cloned().collect();
        let mean = window.iter().sum::<f64>() / (self.window_size as f64);

        let variance = window.iter()
            .map(|&val| (val - mean).powi(2))
            .sum::<f64>() / ((self.window_size - 1) as f64);

        let std_dev = variance.sqrt();

        if std_dev == 0.0 {
            return None;
        }

        let z_score = (new_value - mean).abs() / std_dev;
        Some(z_score)
    }
}

fn main() {
    let mut detector = SlidingWindowDetector::new(3);
    let readings = vec![10.0, 12.0, 11.5, 25.0, 13.0];
    let mut results = Vec::new();

    for &reading in &readings {
        if let Some(z) = detector.add_and_check(reading) {
            results.push(z);
        } else if detector.data_queue.len() >= detector.window_size - 1 && detector.data_queue.len() > 0 {
            results.push(f64::NAN);
        }
    }

    println!("Z-Score Results: {:?}", results);
}

use std::collections::HashSet;

struct GridMap {
    width: usize,
    height: usize,
    walls: HashSet<(usize, usize)>
}

impl GridMap {
    fn new(width: usize, height: usize, walls: Vec<(usize, usize)>) -> Self {
        let mut wall_set = HashSet::new();
        for &(x, y) in &walls {
            wall_set.insert((x, y));
        }
        GridMap {
            width,
            height,
            walls: wall_set
        }
    }

    fn get_walkable_coords(&self) -> Vec<(usize, usize)> {
        let mut walkable = Vec::new();
        for x in 0..self.width {
            for y in 0..self.height {
                if !self.walls.contains(&(x, y)) {
                    walkable.push((x, y));
                }
            }
        }
        walkable
    }
}

fn main() {
    let width = 10;
    let height = 5;
    let wall_locations = vec![
        (1, 1),
        (2, 1),
        (8, 3),
        (9, 4)
    ].into_iter().map(|(x, y)| (x.min(width-1), y.min(height-1))).collect();

    let map = GridMap::new(width, height, wall_locations);
    let coords = map.get_walkable_coords();

    println!("Found {} walkable tiles for the next pass.", coords.len());
    if let Some(&(x, y)) = coords.first() {
        println!("First tile processed: ({}, {})", x, y);
    }
}

use std::collections::HashMap;

struct ConfigStore {
    settings: HashMap<String, String>,
}

impl ConfigStore {
    fn new() -> Self {
        ConfigStore { settings: HashMap::new() }
    }

    fn process_file(&mut self, file_path: &str) -> Result<(), std::io::Error> {
        let content = std::fs::read_to_string(file_path)?;
        for line in content.lines() {
            let trimmed_line = line.trim();
            if trimmed_line.starts_with("[=")
            { 
                let parts: Vec<&str> = trimmed_line.splitn(2, "[=").collect();
                if parts.len() == 2 {
                    let key = parts[0].trim_matches(|c: char| c == '[' || c == '"' || c == '\'');
                    let value = parts[1].trim_matches(|c: char| c == ']' || c == '"' || c == '\'');
                    self.settings.insert(key.to_string(), value.to_string());
                }
            }
        }
        Ok(())
    }

    fn get(&self, key: &str) -> Option<&String> {
        self.settings.get(key)
    }
}

fn main() {
    let mut store = ConfigStore::new();
    match store.process_file("config.txt") {
        Ok(_) => {
            println!("Configuration loaded successfully.");
            if let Some(version) = store.get("service_version") {
                println!("Found service version: {}", version);
            }
        },
        Err(e) => {
            eprintln!("Error reading configuration file: {}", e);
        }
    }
}
